Брутит **облачные бакеты** (AWS S3 + Google Cloud Storage + Azure Blob) по пермутациям имени из ключевого слова (обычно бренда/домена компании). Генерит варианты вида `brand`, `brand-dev`, `brand-prod`, `brand-backup`, `brand-assets`, `dev-brand` и т.п., затем дёргает публичные REST-эндпоинты каждого провайдера БЕЗ авторизации и читает оракул по HTTP-коду: `404` = бакета нет, `403` = бакет есть, но приватный, `200` = публичный и листится. Полезно для поиска забытых/мисконфигнутых хранилищ с данными.

> Никакие ключи не нужны: проверки полностью анонимны (анонимный GET к `s3.amazonaws.com`, `storage.googleapis.com`, `*.blob.core.windows.net`). Найденный `[PUBLIC]`/`[PRIVATE-EXISTS]` бакет дальше изучай скриптом `bucket_access.sh`.

```python
#!/usr/bin/env python3
# bucket_brute.py - ARS3NAL (GPL-3.0). Only for AUTHORIZED testing.
# Permutation brute of S3 / GCS / Azure buckets, anonymous 404/403/200 oracle.
import argparse, concurrent.futures as cf, sys, urllib.request, urllib.error

AFFIX = ["", "dev", "prod", "stage", "staging", "test", "qa", "backup", "backups",
         "assets", "static", "media", "uploads", "files", "data", "db", "logs",
         "public", "private", "internal", "cdn", "images", "img", "web", "app",
         "bucket", "s3", "storage", "archive", "old", "new", "tmp", "temp"]
SEP = ["", "-", ".", "_"]

def permutations(words):
    seen, out = set(), []
    for w in words:
        w = w.strip().lower()
        if not w:
            continue
        for a in AFFIX:
            for s in SEP:
                for name in ((w if a == "" else w + s + a), (w if a == "" else a + s + w)):
                    if name and name not in seen and 3 <= len(name) <= 63:
                        seen.add(name); out.append(name)
    return out

def http_code(url):
    req = urllib.request.Request(url, method="GET",
                                 headers={"User-Agent": "ARS3NAL-bucket/1.0"})
    try:
        with urllib.request.urlopen(req, timeout=10) as r:
            return r.status, r.read(512)
    except urllib.error.HTTPError as e:
        return e.code, b""
    except Exception:
        return None, b""

def classify(code):
    if code == 200:
        return "PUBLIC"
    if code in (403, 401):
        return "PRIVATE-EXISTS"
    return None  # 404 / error -> skip

PROVIDERS = {
    "s3":    lambda n: f"https://{n}.s3.amazonaws.com/",
    "gcs":   lambda n: f"https://storage.googleapis.com/{n}/",
    "azure": lambda n: f"https://{n}.blob.core.windows.net/?comp=list",
}

def check(provider, name):
    url = PROVIDERS[provider](name)
    code, _ = http_code(url)
    verdict = classify(code)
    return (provider, name, code, verdict, url) if verdict else None

def main():
    ap = argparse.ArgumentParser(description="ARS3NAL S3/GCS/Azure bucket permutation brute")
    ap.add_argument("keywords", nargs="+", help="base words (brand, domain stem, project)")
    ap.add_argument("-p", "--providers", default="s3,gcs,azure", help="comma list: s3,gcs,azure")
    ap.add_argument("-w", "--workers", type=int, default=20)
    a = ap.parse_args()
    provs = [p for p in a.providers.split(",") if p in PROVIDERS]
    names = permutations(a.keywords)
    print(f"[*] {len(names)} names x {len(provs)} providers = {len(names)*len(provs)} checks", file=sys.stderr)
    jobs = [(p, n) for p in provs for n in names]
    with cf.ThreadPoolExecutor(max_workers=a.workers) as ex:
        for res in ex.map(lambda j: check(*j), jobs):
            if res:
                pr, nm, code, vd, url = res
                tag = "[PUBLIC]" if vd == "PUBLIC" else "[PRIVATE-EXISTS]"
                print(f"{tag:18} {pr:5} {code}  {url}")

if __name__ == "__main__":
    main()
```

Запуск:
```bash
python3 bucket_brute.py acme acmecorp acme-inc -p s3,gcs,azure
# публичные/приватные находки изучи через bucket_access.sh
```
